VALUES
  ('optometrist-moex-01084', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '若視野呈現雙顳側半盲（bitemporalhemianopia），其病灶為下列何者？', '["視神經（opticnerve）", "視徑（optictract）", "視放射（opticradiations）", "視神經交叉（opticchiasm）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01085', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '眼外肌由許多對腦神經控制，下列那一對腦神經與眼外肌運動控制無關？', '["第三對", "第二對", "第四對", "第六對"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01086', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關眼外肌及其神經控制之敘述，下列何者錯誤？', '["外旋神經（abducensnerve）損傷會導致外直肌麻痺，出現內斜視（esotropia）", "第四對腦神經損傷，病患頭部會傾斜遠離患側肩膀的方向，以修正失去了拮抗的下斜肌所引發的外旋 （extorsion）", "當眼睛往下看時下直肌收縮，上直肌放鬆，同時提上眼瞼肌放鬆而眼瞼垂下，此乃遵循海利氏定律 （Hering’slaw）", "第四對腦神經麻痺可以Park’s三步驟測試（Park’s3-steptest）來評估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01087', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '在斜視的情況下，患者視物時常會以異常的頭部姿勢來適應，稱為斜視的運動適應（motor adaptation to strabismus），下列有關斜視的運動適應之敘述何者錯誤？', '["若使眼球向右看的肌肉其中之一麻痺了（例如右眼外直肌麻痺），患者臉部將轉向左側視物", "若雙眼任何一提升肌（elevatormuscle）無力，患者下巴將抬高視物", "若左眼上斜肌麻痺，患者頭部將傾斜向右肩視物", "斜視患者發生斜視的運動適應是為了要保持雙眼單一影像視覺（binocularsinglevision,BSV）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01088', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '虹彩血管血液供應主要來自那幾條血管？①中心網膜動脈（centralretinalartery）  ②短後睫狀動脈（short', '["長後睫狀動脈（longposteriorciliaryartery）", "前睫狀動脈（anteriorciliaryartery）", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01089', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '眼外直肌的血液供應通常由來自眼動脈（ophthalmicartery）的前睫狀動脈（anteriorciliaryartery），下列何 外眼直肌的前睫狀動脈是來自淚動脈（lacrimalartery）？', '["內直肌", "外直肌", "上直肌", "下直肌"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01090', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '眼動脈（ophthalmicartery）為下列何者的分支？', '["基底動脈（basilarartery）", "椎動脈（vertebralcarotidartery）", "外頸動脈（externalcarotidartery）", "內頸動脈（internalcarotidartery）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01091', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '下列何者並未受到副交感神經（parasympatheticnerve）所支配？', '["淚腺", "鞏膜", "虹膜", "睫狀體"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01092', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關調節反射（accommodationreflex）的敘述，下列何者錯誤？', '["當眼睛從遠處移向近處物體時，光波的傳入衝動穿過視神經、視交叉、視覺皮層到達額葉皮層的眼球區", "額葉皮質纖維下行到中腦的動眼神經核，使內直肌收縮，帶來內聚", "下降的皮質纖維與兩側動眼神經的副交感神經核（Edinger-Westphal核）突觸，節前纖維到達睫狀神經節", "節後副交感神經纖維作用使睫狀肌放鬆和瞳孔收縮來增加其屈光力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01093', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '關於網膜電位圖（ERG）檢查的敘述，下列何者正確？', '["形態網膜電位圖（patternERG）主要是檢測網膜神經節細胞（ganglioncell）的功能", "網膜電位圖檢查的a波主要是由穆勒細胞（Müllercell）所產生", "網膜電位圖可測知網膜色素細胞（RPEcell）的功能", "網膜電位圖檢查中30Hz連續閃爍（30Hzflicker）測試主要是檢測桿狀細胞的功能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
